# Unit Tests for `safe_divide`

```python
import pytest
from your_module import safe_divide


# ---------------------------------------------------------------------------
# Happy path
# ---------------------------------------------------------------------------

class TestSafeDivideHappyPath:
    def test_divides_two_positive_integers(self):
        assert safe_divide(10, 2) == 5.0

    def test_divides_two_floats(self):
        assert safe_divide(7.5, 2.5) == 3.0

    def test_divides_positive_by_negative(self):
        assert safe_divide(10, -2) == -5.0

    def test_divides_negative_by_negative(self):
        assert safe_divide(-10, -2) == 5.0

    def test_divides_negative_by_positive(self):
        assert safe_divide(-10, 2) == -5.0

    def test_zero_numerator_nonzero_denominator(self):
        assert safe_divide(0, 5) == 0.0

    def test_returns_float(self):
        result = safe_divide(10, 2)
        assert isinstance(result, float)

    def test_large_numbers(self):
        assert safe_divide(1e18, 1e9) == pytest.approx(1e9)

    def test_small_fractional_numbers(self):
        assert safe_divide(0.1, 0.2) == pytest.approx(0.5)


# ---------------------------------------------------------------------------
# Default / zero-division behaviour
# ---------------------------------------------------------------------------

class TestSafeDivideZeroDivision:
    def test_int_zero_denominator_returns_default(self):
        assert safe_divide(10, 0) == 0.0

    def test_float_zero_denominator_returns_default(self):
        assert safe_divide(10.0, 0.0) == 0.0

    def test_zero_divided_by_zero_returns_default(self):
        assert safe_divide(0, 0) == 0.0

    def test_custom_default_is_returned_on_zero_division(self):
        assert safe_divide(10, 0, default=-1.0) == -1.0

    def test_custom_default_zero_explicit(self):
        assert safe_divide(5, 0, default=0.0) == 0.0

    def test_custom_default_large_value(self):
        assert safe_divide(1, 0, default=999.0) == 999.0

    def test_custom_default_negative_value(self):
        assert safe_divide(1, 0, default=-42.0) == -42.0


# ---------------------------------------------------------------------------
# Edge cases
# ---------------------------------------------------------------------------

class TestSafeDivideEdgeCases:
    def test_denominator_very_close_to_zero_but_not_zero(self):
        """Should NOT trigger the default; Python floats handle this as inf."""
        result = safe_divide(1.0, 1e-308)
        assert result > 0  # extremely large but not the default

    def test_result_is_approximate_for_irrational_division(self):
        assert safe_divide(1, 3) == pytest.approx(0.3333333333)

    def test_both_arguments_are_zero_float(self):
        assert safe_divide(0.0, 0.0) == 0.0

    def test_default_is_not_used_for_normal_division(self):
        """Passing a custom default should not affect a normal division."""
        assert safe_divide(9, 3, default=99.0) == 3.0

    def test_negative_zero_denominator(self):
        """-0.0 is equal to 0.0 in Python; ZeroDivisionError is still raised."""
        assert safe_divide(5, -0.0) == 0.0

    def test_infinity_numerator(self):
        import math
        result = safe_divide(float("inf"), 2)
        assert math
